blocks.body:
{
    "level": "B2–C1",
    "intro": "W tej lekcji poznasz <strong>bierny bezokolicznik</strong>: <strong>to be done</strong> i <strong>to have been done</strong>. Zobaczysz, kiedy używać każdej formy.",
    "rules": [
        {
            "label": "Prosty",
            "color": "emerald",
            "text": "<strong>to be + V3</strong> — czynność teraźniejsza lub przyszła:",
            "example": "The report needs to be finished."
        },
        {
            "label": "Perfect form",
            "color": "blue",
            "text": "<strong>to have been + V3</strong> — wcześniejsza czynność:",
            "example": "He seems to have been promoted."
        },
        {
            "label": "Porównanie",
            "color": "rose",
            "text": "Czynnie: <strong>to do / to have done</strong> → biernie: <strong>to be done / to have been done</strong>",
            "example": "to write → to be written → to have been written"
        }
    ]
}

{
    "title": "1. Tworzenie bezokolicznika biernego",
    "intro": "Porównanie form czynnych i biernych bezokolicznika:",
    "items": [
        {
            "label": "Bezokolicznik czynny",
            "title": "robić/pisać",
            "subtitle": "Chcę napisać list. - Chcę napisać list."
        },
        {
            "label": "Bezokolicznik bierny",
            "title": "to be done / to be written",
            "subtitle": "List trzeba napisać. - Trzeba pisać listy."
        },
        {
            "label": "Perfect czynny",
            "title": "to have done / to have written",
            "subtitle": "Twierdzi, że napisał tę książkę. - Twierdzi, że napisał książkę."
        },
        {
            "label": "Perfect bierny",
            "title": "to have been done / to have been written",
            "subtitle": "Książka sprawia wrażenie, jakby została napisana dawno temu. - Wygląda na to, że książka została napisana dawno temu."
        }
    ]
}

{
    "title": "2. Prosty bezokolicznik bierny (to be done)",
    "sections": [
        {
            "label": "Po need / want / expect",
            "color": "emerald",
            "description": "Kiedy ktoś chce/oczekuje <strong>coś, co zostanie zrobione</strong>:",
            "examples": [
                {
                    "en": "The report needs to be finished by Friday.",
                    "ua": "Raport musi być gotowy do piątku."
                },
                {
                    "en": "I want this issue to be resolved immediately.",
                    "ua": "Chcę, żeby ta sprawa została natychmiast rozwiązana."
                },
                {
                    "en": "They expect the project to be approved.",
                    "ua": "Oczekują, że projekt zostanie zatwierdzony."
                },
                {
                    "en": "The car needs to be repaired.",
                    "ua": "Samochód wymaga naprawy."
                }
            ]
        },
        {
            "label": "Po seem / appear",
            "color": "blue",
            "description": "Aby wyrazić <strong>wrażenie lub przypuszczenie</strong>:",
            "examples": [
                {
                    "en": "The door seems to be locked.",
                    "ua": "Wygląda na to, że drzwi są zamknięte."
                },
                {
                    "en": "He appears to be respected by everyone.",
                    "ua": "Wygląda na to, że wszyscy go szanują."
                },
                {
                    "en": "The problem appears to be solved.",
                    "ua": "Wydaje się, że problem został rozwiązany."
                }
            ]
        },
        {
            "label": "Po would like / prefer",
            "color": "amber",
            "description": "Aby wyrazić <strong>pragnienie lub preferencję</strong>:",
            "examples": [
                {
                    "en": "I would like to be informed about the decision.",
                    "ua": "Chcę zostać poinformowany o decyzji."
                },
                {
                    "en": "She prefers to be left alone.",
                    "ua": "Woli zostawać sama."
                },
                {
                    "en": "We would like to be invited to the meeting.",
                    "ua": "Chcielibyśmy zostać zaproszeni na spotkanie."
                }
            ]
        }
    ]
}

{
    "title": "3. Idealny bezokolicznik bierny (to be done)",
    "sections": [
        {
            "label": "Wcześniejsza czynność",
            "color": "emerald",
            "description": "Wskazuje czynność, która <strong>zdarzyła się</strong> przed głównym czasownikiem:",
            "examples": [
                {
                    "en": "He seems to have been promoted last month.",
                    "ua": "Wygląda na to, że awansował w zeszłym miesiącu."
                },
                {
                    "en": "The documents appear to have been lost.",
                    "ua": "Wygląda na to, że dokumenty zaginęły."
                },
                {
                    "en": "The letter seems to have been sent already.",
                    "ua": "Wygląda na to, że e-mail został już wysłany."
                }
            ]
        },
        {
            "label": "Struktury raportowania",
            "color": "blue",
            "description": "W konstrukcjach bezosobowych z <strong>mówi się / wierzy / podaje się / wiadomo</strong>:",
            "examples": [
                {
                    "en": "He is believed to have been kidnapped.",
                    "ua": "Uważa się, że został porwany."
                },
                {
                    "en": "She is reported to have been seen in Paris.",
                    "ua": "Według doniesień widziano ją w Paryżu."
                },
                {
                    "en": "The painting is thought to have been stolen.",
                    "ua": "Uważa się, że obraz został skradziony."
                },
                {
                    "en": "He is known to have been educated in Oxford.",
                    "ua": "Wiadomo, że studiował w Oksfordzie."
                }
            ]
        },
        {
            "label": "Po modach + mieć",
            "color": "rose",
            "description": "W przypadku <strong>założeń dotyczących przeszłości</strong>:",
            "examples": [
                {
                    "en": "The work should have been completed yesterday.",
                    "ua": "Prace powinny zakończyć się wczoraj."
                },
                {
                    "en": "The message must have been deleted.",
                    "ua": "Wiadomość musiała zostać usunięta."
                },
                {
                    "en": "The car could have been stolen.",
                    "ua": "Samochód mógł zostać skradziony."
                }
            ]
        }
    ]
}

{
    "title": "4. Czasowniki połączone z bezokolicznikiem biernym",
    "sections": [
        {
            "label": "Oczekiwanie/pragnienie",
            "color": "emerald",
            "description": "<strong>chcę, potrzebuję, oczekuję, chciałbym, wolę, życzę</strong>:",
            "examples": [
                {
                    "en": "I expect to be paid on time.",
                    "ua": "Oczekuję wypłaty na czas."
                },
                {
                    "en": "Nobody wants to be forgotten.",
                    "ua": "Nikt nie chce być zapomniany."
                },
                {
                    "en": "The floor needs to be cleaned.",
                    "ua": "Podłogę trzeba umyć."
                }
            ]
        },
        {
            "label": "Wydaje się/wygląda",
            "color": "blue",
            "description": "<strong>wydaje się, pojawia się, zdarza się, okazuje się, udowadnia</strong>:",
            "examples": [
                {
                    "en": "He seems to be trusted by his colleagues.",
                    "ua": "Wygląda na to, że koledzy mu ufają."
                },
                {
                    "en": "The theory turned out to be proven wrong.",
                    "ua": "Teoria została obalona."
                },
                {
                    "en": "She happened to be chosen for the role.",
                    "ua": "Tak się złożyło, że została wybrana do tej roli."
                }
            ]
        },
        {
            "label": "Konstrukcje bezosobowe",
            "color": "amber",
            "description": "<strong>mówi się, uważa się, donosi się, wiadomo, uważa się</strong>:",
            "examples": [
                {
                    "en": "He is said to be very intelligent.",
                    "ua": "Mówią, że jest bardzo mądry."
                },
                {
                    "en": "They are believed to be innocent.",
                    "ua": "Uważa się, że są niewinni."
                },
                {
                    "en": "The company is reported to be expanding.",
                    "ua": "Podobno firma się rozwija."
                }
            ]
        }
    ]
}

{
    "title": "5. Porównanie: to be done i to have been done",
    "intro": "Kiedy używać prostego lub doskonałego bezokolicznika strony biernej:",
    "rows": [
        {
            "en": "to be done",
            "ua": "Teraźniejsze/przyszłe działanie",
            "note": "Wygląda na to, że jest szanowany. - Mówimy o sytuacji teraz."
        },
        {
            "en": "to have been done",
            "ua": "Czynność wcześniejsza",
            "note": "Wygląda na to, że dostał awans. - Awans wydarzył się wcześniej."
        },
        {
            "en": "to be done (need)",
            "ua": "Potrzeba wykonania czynności",
            "note": "Tę pracę trzeba dokończyć. - Chodzi o zadanie, które nadal czeka."
        },
        {
            "en": "to have been done (should)",
            "ua": "Krytyka dotychczasowej bierności",
            "note": "Praca powinna była zostać ukończona. - Mówimy o wcześniejszym obowiązku."
        }
    ],
    "warning": "📌 Bezokolicznik doskonały wskazuje czynność, która wydarzyła się PRZED czasownikiem głównym!"
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie elementu <strong>to be</strong> w biernym bezokoliczniku.",
            "wrong": "The report needs finished.",
            "right": "✅ The report needs to be finished."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V1 zamiast V3.",
            "wrong": "She wants to be invite.",
            "right": "✅ She wants to be invited."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie prostego i doskonałego.",
            "wrong": "He seems to be promoted last year.",
            "right": "✅ He seems to have been promoted last year."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów w formie perfect.",
            "wrong": "to been have done",
            "right": "✅ to have been done"
        }
    ]
}
